const items = $input.all();
const seen = new Set();
const result = [];
const maxAge = 3 * 24 * 60 * 60 * 1000;
const now = Date.now();

for (const item of items) {
  const d = item.json;
  const title = (d.title || '').trim();
  const content = (d.contentSnippet || d.content || '').replace(/<[^>]*>/g, '').trim();

  if (!title || content.length < 50) continue;

  if (d.isoDate || d.pubDate) {
    try {
      const pub = new Date(d.isoDate || d.pubDate).getTime();
      if (now - pub > maxAge) continue;
    } catch(e) {}
  }

  const key = title.toLowerCase().replace(/[^a-z\u0430-\u044f\u04510-9]/gi, '').substring(0, 60);
  if (seen.has(key)) continue;
  seen.add(key);

  const link = d.link || '';
  let source = 'Other';
  if (link.includes('constructiondive')) source = 'Construction Dive';
  else if (link.includes('enr.com')) source = 'ENR';
  else if (link.includes('dezeen')) source = 'Dezeen';
  else if (link.includes('futuretools')) source = 'Future Tools';
  else if (link.includes('archdaily')) source = 'ArchDaily';

  result.push({
    json: {
      source: source,
      title: title,
      link: link,
      content: content.substring(0, 500),
      pubDate: d.isoDate || d.pubDate || ''
    }
  });
}

return result.length > 0 ? result : [];

const items = $input.all();
const analyses = [];

for (const item of items) {
  let text = '';
  try {
    if (item.json.output && Array.isArray(item.json.output)) {
      text = item.json.output[0].content[0].text || '';
    } else if (item.json.content && Array.isArray(item.json.content)) {
      text = item.json.content[0].text || '';
    } else if (item.json.message && item.json.message.content) {
      text = item.json.message.content;
    } else if (item.json.text) {
      text = item.json.text;
    }
  } catch(e) {
    text = JSON.stringify(item.json);
  }

  const lower = (text || '').toLowerCase();
  if (text && !lower.includes('relevant: no') && !lower.includes('no signal') && text.trim().length > 10) {
    analyses.push(text);
  }
}

if (analyses.length === 0) {
  return [];
}

return [{ json: { aggregated: analyses.join('\n\n---\n\n'), count: analyses.length } }];
